import {
  html,
  customElement,
  when,
} from "@umbraco-cms/backoffice/external/lit";
import { UmbModalBaseElement } from "@umbraco-cms/backoffice/modal";
import type { UserItemResponseModel } from "@umbraco-cms/backoffice/external/backend-api";
import { UMB_ACTION_EVENT_CONTEXT } from "@umbraco-cms/backoffice/action";
import { FORMS_SECURITY_USER_FOLDER_ENTITY_TYPE } from "../../../entities.js";
import { FormsSecurityUserDetailRepository } from "../../../repository/index.js";
import type { FormsUserSecurityCreateOptionsModalData } from "./index.js";
import { UUISelectElement } from "@umbraco-cms/backoffice/external/uui";
import { UmbRequestReloadChildrenOfEntityEvent } from "@umbraco-cms/backoffice/entity-action";

const elementName = "forms-user-security-create-options-modal";

@customElement(elementName)
export class FormsUserSecurityCreateOptionsModalElement extends UmbModalBaseElement<FormsUserSecurityCreateOptionsModalData> {
  #users: Array<UserItemResponseModel> = [];
  #repository = new FormsSecurityUserDetailRepository(this);

  constructor() {
    super();

    this.#initialize();
  }

  async #initialize() {
    this.#users = await this.#repository.requestUsersToAssign();
    this.requestUpdate();
  }

  async #onCreateClick() {
    const selectedUserId = this.#getSelectedUserId();
    await this.#createUser(selectedUserId);

    this.#reloadTree();
    this._submitModal();

    // Redirect to created user screen.
    history.pushState(
      {},
      "",
      `/umbraco/section/forms/workspace/forms-security-user/edit/${selectedUserId}/view/permissions`
    );
  }

  #getSelectedUserId() {
    const selectElement = this.shadowRoot?.getElementById(
      "users"
    ) as UUISelectElement;
    return selectElement.value.toString();
  }

  async #createUser(userId: string) {
    const { data } = await this.#repository.createScaffold({ unique: userId });
    await this.#repository.create(data!, null);
  }

  async #reloadTree() {
    const reloadEvent = new UmbRequestReloadChildrenOfEntityEvent({
      entityType: FORMS_SECURITY_USER_FOLDER_ENTITY_TYPE,
      unique: "207c2294-970b-4e1f-82fd-ae8996ef171d", // Matches FormBuilderWeb.Controllers.ManagementApi.Security.Tree.SecurityTreeControllerBase.UsersFolderId
    });
    const eventContext = await this.getContext(UMB_ACTION_EVENT_CONTEXT);
    eventContext.dispatchEvent(reloadEvent);
  }

  render() {
    return html`<umb-body-layout
      headline=${this.localize.term("formSecurity_createTitle")}
    >
      <uui-box>
        <p>${this.localize.term("formSecurity_createUserRecordNote")}</p>
        ${when(
          this.#users.length === 0,
          () =>
            html`<p>
              ${this.localize.term("formSecurity_allUsersHaveRecords")}
            </p>`
        )}
        ${when(
          this.#users.length > 0,
          () => html` <uui-select
            id="users"
            label="User"
            .options=${this.#users.map((u) => ({ name: u.name, value: u.id }))}
          >
          </uui-select>`
        )}
      </uui-box>
      <uui-button
        slot="actions"
        label=${this.localize.term("general_cancel")}
        @click=${this._rejectModal}
        ></uui-button
      >
      ${when(
        this.#users.length > 0,
        () =>
          html`<uui-button
            slot="actions"
            label=${this.localize.term("general_create")}
            look="primary"
            color="positive"
            @click=${this.#onCreateClick}
            ></uui-button
          >`
      )}
    </umb-body-layout>`;
  }
}

export default FormsUserSecurityCreateOptionsModalElement;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsUserSecurityCreateOptionsModalElement;
  }
}
